#include <iostream>
#include <string>

class Animal {
protected:
    std::string name;
    int health;

public:
    Animal(std::string n, int h) : name(n), health(h) {}

    virtual ~Animal() {}

    // Base method — can be overridden
    virtual void makeSound() const {
        std::cout << name << " makes a generic animal sound." << std::endl;
    }

    // Another virtual method
    virtual void move() const {
        std::cout << name << " moves around." << std::endl;
    }

    // Non-virtual method — can't be overridden
    void breathe() const {
        std::cout << name << " breathes." << std::endl;
    }

    virtual void displayInfo() const {
        std::cout << name << " (Health: " << health << ")" << std::endl;
    }
};

class Dog : public Animal {
public:
    Dog(std::string n, int h) : Animal(n, h) {}

    // Override makeSound
    void makeSound() const override {
        std::cout << name << " barks: Woof! Woof!" << std::endl;
    }

    // Override move
    void move() const override {
        std::cout << name << " runs on four legs." << std::endl;
    }

    // New method specific to Dog
    void wagTail() const {
        std::cout << name << " wags tail happily!" << std::endl;
    }
};

class Cat : public Animal {
public:
    Cat(std::string n, int h) : Animal(n, h) {}

    void makeSound() const override {
        std::cout << name << " meows: Meow~" << std::endl;
    }

    void move() const override {
        std::cout << name << " slinks silently." << std::endl;
    }

    void purr() const {
        std::cout << name << " purrs contentedly." << std::endl;
    }
};

class Wolf : public Dog {
public:
    Wolf(std::string n, int h) : Dog(n, h) {}

    void makeSound() const override {
        std::cout << name << " howls: Awooooooo!" << std::endl;
    }

    void move() const override {
        std::cout << name << " stalks with pack." << std::endl;
    }
};

int main() {
    std::cout << "=== Method Overriding ===" << std::endl;

    // Creating objects
    Animal generic("Generic", 100);
    Dog rex("Rex", 120);
    Cat whiskers("Whiskers", 80);
    Wolf shadow("Shadow", 150);

    // Direct calls
    generic.makeSound();
    rex.makeSound();
    whiskers.makeSound();
    shadow.makeSound();

    std::cout << "\n=== Polymorphism ===" << std::endl;

    // Array of Animal pointers
    Animal* animals[] = {&generic, &rex, &whiskers, &shadow};

    for (Animal* animal : animals) {
        animal->makeSound();
        animal->move();
        animal->breathe();  // Can't be overridden
        std::cout << std::endl;
    }

    // Can't call Dog-specific methods through Animal pointer
    // animals[1]->wagTail();  // ERROR!

    // But we can downcast (if we're sure)
    Dog* dogPtr = dynamic_cast<Dog*>(animals[1]);
    if (dogPtr) {
        dogPtr->wagTail();
    }

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <string>

class Base {
public:
    // Forgot 'virtual'!
    void speak() {
        std::cout << "Base speaks" << std::endl;
    }
};

class Derived : public Base {
public:
    // Trying to override without virtual
    void speak() override {  // ERROR!
        std::cout << "Derived speaks" << std::endl;
    }
};

int main() {
    Base* obj = new Derived();
    obj->speak();  // Calls Base::speak, not Derived!
    return 0;
}

phase2.explanation:
You marked `speak` as `override` but the base method isn't `virtual`!

**What's happening:**
1. Base::speak is not virtual
2. Derived::speak tries to override but can't
3. The `override` keyword catches the error

**The fix:**
```cpp
class Base {
public:
    virtual void speak() {  // ← Add virtual!
        std::cout << "Base speaks" << std::endl;
    }
};
```

**PlusPlus-chan says:**
"This is why we use `override`! It catches errors like this. Without it, the code would compile but not work correctly."

