#include <iostream>
#include <string>

class Weapon {
protected:
    std::string name;
    int damage;

public:
    Weapon(std::string n, int d) : name(n), damage(d) {}

    virtual ~Weapon() {}

    virtual void use() const {
        std::cout << name << " deals " << damage << " damage." << std::endl;
    }

    virtual void display() const {
        std::cout << name << " (Damage: " << damage << ")" << std::endl;
    }
};

class Sword : public Weapon {
private:
    int sharpness;

public:
    Sword(std::string n, int d, int s) : Weapon(n, d), sharpness(s) {}

    void use() const override {
        int totalDamage = damage + sharpness;
        std::cout << name << " slashes for " << totalDamage << " damage!" << std::endl;
    }

    void display() const override {
        Weapon::display();
        std::cout << "  Sharpness: " << sharpness << std::endl;
    }
};

class Bow : public Weapon {
private:
    int range;

public:
    Bow(std::string n, int d, int r) : Weapon(n, d), range(r) {}

    void use() const override {
        std::cout << name << " fires an arrow for " << damage 
                  << " damage from " << range << " meters!" << std::endl;
    }

    void display() const override {
        Weapon::display();
        std::cout << "  Range: " << range << "m" << std::endl;
    }
};

int main() {
    Sword sword("Iron Sword", 15, 5);
    Bow bow("Longbow", 12, 50);

    std::cout << "=== Weapons ===" << std::endl;
    sword.display();
    bow.display();

    std::cout << "\n=== Using Weapons ===" << std::endl;
    sword.use();
    bow.use();

    std::cout << "\n=== Polymorphism ===" << std::endl;
    Weapon* weapons[] = {&sword, &bow};
    for (Weapon* w : weapons) {
        w->display();
        w->use();
        std::cout << std::endl;
    }

    return 0;
}
